var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"야단났군…….","JPN":"まいったな……","ENG":"This is troublesome...","TWN":"真是一團糟……"},"stage":{"bg":"SS_ESPR_06","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"눈으로 보고도 믿을 수가 없을 정도야.","JPN":"この目で見ても信じられない。","ENG":"I can't believe what I'm seeing in front of my eyes.","TWN":"就算親眼見到了都覺得難以置信。"},"stage":{"bg":"SS_ESPR_06","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"이곳의 숲, 아니…… 이 세계 자체가 저 파편에게 탐식당하고 있는 건가?","JPN":"この森、いや……この世界自体があの破片に侵食されているのか？","ENG":"Is this forest... No, is the world itself being devoured by that Fragment?","TWN":"這裡的樹林，不……整個世界都在被那個碎片所吞噬嗎？"},"stage":{"bg":"SS_ESPR_06","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"LAKE-4에 격리되어있던 파편과는 비교조차 할 수 없어.","JPN":"LAKE-4に隔離されていた破片とは比べ物にならない。","ENG":"It's incomparable to the Fragment that was quarantined at LAKE-4.","TWN":"根本無法與隔離在LAKE-4上的碎片比較。"},"stage":{"bg":"SS_ESPR_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그나마 다행인 건 봉인 사슬이 없는데도 공격성을 보이지 않는 점이라고 해야겠지.","JPN":"封印の鎖がなくても攻撃してこないのが幸いだな。","ENG":"The only good news is that even without the Sealing Chains, it seems to show no signs of aggressiveness.","TWN":"值得慶倖的是，即使沒有封印鎖鏈，也沒有表現出攻擊性。"},"stage":{"bg":"SS_ESPR_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그렇다면 아직 자의식을 가지지 않았을 때가 기회일지도 모르겠군.","JPN":"それなら、まだ自我をもっていない今がチャンスかもしれない。","ENG":"Then, perhaps there might be an opportunity to kill it before it gains self-consciousness.","TWN":"若是如此，在還沒有自我意識的時候，也許就是機會。"},"stage":{"bg":"SS_ESPR_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"오, 오오…….","JPN":"お、おお……","ENG":"Oh... Ooh...!","TWN":"喔，喔喔……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"살아서 내 눈으로 저런 광경을 목격하게 될 줄이야.","JPN":"生きているうちにこんな景色を目にすることができるとは。","ENG":"I never thought I'd see such a sight like this during my lifetime.","TWN":"沒想到我還活著的時候就能親眼目睹此等情景。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"저것이야 말로…… 신의 피를 담은 그릇. 성배의 진정한 모습이네.","JPN":"あれこそ……神の血を宿した器、聖杯の真の姿だ。","ENG":"That is... the vessel for god's blood. The true form of the Holy Grail.","TWN":"那個才是……盛裝著神血的器皿，聖杯的真實面貌。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"누가 입을 열라고 했지? 네놈 생각 따위는 관심 없어.","JPN":"誰が口を開いていいと言った？　貴様の感想など求めてない。","ENG":"Who said you could open your mouth? Nobody cares what you think.","TWN":"誰讓你說話的？我對你這傢伙的想法並不感興趣。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 저걸 현실에 부상시켰다간, 대환류 이상의 재난이 벌어질 건 불 보듯 뻔하군.","JPN":"だが、あれを現実に浮上させてしまったら、大還流以上の災厄になるのは確かだ。","ENG":"But if that thing emerges in the Normalside, it'll be an even bigger disaster than the Great Gyre.","TWN":"如果讓它出現在現世中，肯定會發生比大環流更糟糕的災難。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"역시 형님은…….","JPN":"やはり兄貴は……","ENG":"Just as I thought...","TWN":"大哥果然……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"형님께서는 저것의 싹을 제거하기 위해, 그렇게 오랜 시간을…….","JPN":"兄貴はあれの芽を摘み取るために、あんなに長い時間を……","ENG":"Sir Burnett spent all that time to remove that thing for good...","TWN":"是為了斬草除根，才花了那麼長時間……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"자네…… 지금 뭘 하려는 거지?","JPN":"君……今何を考えている？","ENG":"Hey... What do you think you're doing?","TWN":"你……這是要做什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"보면 모르겠나? 성배를 말살할 걸세.","JPN":"見てわからないか？　聖杯を末梢する。","ENG":"Can't you tell? I'm going to destroy the Holy Grail.","TWN":"看不出來嗎？我要銷毀聖杯。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"한심하군. 제정신인가?","JPN":"嘆かわしい、正気か？","ENG":"How pathetic. Are you insane?","TWN":"荒謬，你瘋了嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"제정신이냐고? 물론이야.","JPN":"正気だと？　もちろんだ。","ENG":"Am I insane? No, I'm not.","TWN":"瘋了嗎？當然。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"원래 숙주를 죽이는 건, 파편이 폭주할 가능성이 있어서 위험하지만.","JPN":"破片が暴走する可能性があるから本来は宿主を殺すことは危険とされるが……","ENG":"Normally, eliminating the host would be dangerous as it increases the likelihood of the Fragment causing an outburst, but...","TWN":"殺死宿主有可能讓碎片暴走，會很危險。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"지금은 수단과 방법을 가릴 때가 아니야.","JPN":"今は手段を選んでいる場合ではない。","ENG":"now's not the time to be picky about what strategy I take.","TWN":"但現在不是瞻前顧後的時候。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"설령 파편이 폭주하여 내가 죽게 되더라도…….","JPN":"たとえ破片が暴走して俺が死ぬことになっても……","ENG":"Even if the Fragment goes berserk and I die...","TWN":"縱使碎片暴走，會置我於死地……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"지금, 여기서 마무리 지어야만 해. 저걸 현실에 끌고 갈 수는 없어.","JPN":"ここでけじめをつけなければならない。あれを現実に連れて行くわけにはいかない。","ENG":"I must end it here, so it doesn't find its way to the Normalside.","TWN":"現在也必須要在這裡了結。我不允許把它拖到現世中去。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"유감이군.","JPN":"それは残念だ。","ENG":"That's a shame.","TWN":"真是可惜。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"자네는 저걸 보고도…… 그런 시시한 발상 밖에 떠올리지 못하나?","JPN":"君はあれを目にしてもなお……そんなくだらないことしか考えられないのかい？","ENG":"After seeing that... All you can come up with is something so mediocre.","TWN":"你都親眼看到了此等神蹟……卻還只想著那些無聊的想法嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"신적 존재를 이 두 눈으로 직접 목격할 수 있는 절호의 기회야.","JPN":"神なる存在を目撃する絶好のチャンスだ。","ENG":"This is our chance to witness a godlike being with our own two eyes.","TWN":"這是可以親眼目睹神之存在的絕佳機會。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JAMES_PRYDWEN_NPC_NULL","text":{"KOREA":"평범한 인간이 그런 소중한 기회를……!","JPN":"普通の人間がそんな貴重なチャンスを……！","ENG":"How can someone waste such a precious–","TWN":"平凡之人若是有如此寶貴的機會……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"JAMES_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};